var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대균열을 통해 강림하려는 마왕의 세력을 저지한다라…….","JPN":"大亀裂を通じて降臨しようとしている魔王の勢力を阻止する、か……","ENG":"To block the Demon Lord's forces trying to descend through the Grand Dimension Crevice...","TWN":"要阻止想經由大峽谷降臨的魔王勢力……"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"나쁘지 않은 작전이군.","JPN":"悪くない作戦だな。","ENG":"Not a bad plan at all.","TWN":"是個不錯的作戰呢。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 최고 관리자님께서 직접 제안한 작전이죠.","JPN":"はい、最高管理者の提案による作戦なんです。","ENG":"Yes. It was proposed directly by the Supreme Administrator.","TWN":"是的，這是最高管理者親自提議的計畫。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>콜로서스 베이스</color>를 통해 선로전환기를 제작 중이에요.","JPN":"現在、<color=#ffd34c>コロッサスベース</color>を使って線路転換器を製作しています。","ENG":"We're producing the Track Switcher through the <color=#ffd34c>Colossus Base</color>.","TWN":"我們正透過<color=#ffd34c>巨像基地</color>製造線路轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다만, 프론트 베이는 한 가지 확인하고 싶은 점이 있어 들르게 되었어요.","JPN":"ただ、フロントベイは1つ確認しておきたい点がありましたので、寄らせていただきました。","ENG":"However, there was one thing I needed to verify here in Front Bay.","TWN":"但前灣有件事想確認一下，所以過來了。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 대답해 줄 수 있는 거라면 뭐든지.","JPN":"私に答えられることならば。","ENG":"If it's something I can answer, go ahead.","TWN":"只要我能回答，隨便妳問。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 참고한 장치.","JPN":"線路転換器はエタニウムドライブを参考にした装置。","ENG":"The Track Switcher is modeled after the Eternium Drive.","TWN":"線路轉換器是永恆之金引擎製造的裝置。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"가동 범위가 명확하므로 최대한 대균열의 근처에서 사용해야 해요.","JPN":"稼働範囲が限られていますから、なるべく大亀裂の近くで使用する必要があります。","ENG":"Its operating range is fixed, so it must be used as close to the Grand Dimension Crevice as possible.","TWN":"啟動範圍有限，因此必須在靠近大峽谷的地方使用。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"프론트 베이 주변의 지도를 살펴봤는데, 때마침 알맞은 장소가 있더라고요.","JPN":"そこで、フロントベイ周辺の地図を調べたのですが、ちょうど良さそうな場所を見つけたんです。","ENG":"I reviewed the map around Front Bay, and there just so happened to be a suitable location.","TWN":"我看了前灣周邊地圖，發現剛好有個合適的地點。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대균열 근처의 섬이라면… 마하 섬을 얘기하는 거로군.","JPN":"大亀裂近くの島というと……マッハ島か。","ENG":"If you mean an island near the Grand Dimension Crevice... you're talking about Macha Island.","TWN":"靠近大峽谷的島……是指瑪查島吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 우리는 다른 방법을 찾아야 할 거야.","JPN":"だったら他の方法を探した方がいい。","ENG":"Then we'll need to find another option.","TWN":"那麼我們得另尋方法了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아~ 대균열 근처라는 점, 크라켄의 영역 한 가운데라는 점,","JPN":"ああ、大亀裂付近だということ、クラーケンの縄張りの真ん中だということ、","ENG":"Ah! Considering it's right by the Grand Dimension Crevice, at the heart of Kraken's territory,","TWN":"啊～因為靠近大峽谷、位在克拉肯領域中央、"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 검은 범람이 발생할 때마다 해수면이 높아진다는 점을 고려한다면…….","JPN":"そして黒い氾濫が発生するたびに海水面が上昇するということを考えると……","ENG":"and seeing how sea levels rise during every Black Flood...","TWN":"再加上洪災發生時海面會上升……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마하 섬은 지금 바닷속에 잠겨있겠네요.","JPN":"マッハ島は今、海の中に沈んでいるんですね。","ENG":"Macha Island would be underwater right now.","TWN":"瑪查島現在應該沉在海裡了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"음, 이러면 살짝 곤란해졌는걸요?","JPN":"うーん、これだと少し困りますね。","ENG":"Mm, that's going to be a bit of a problem.","TWN":"嗯，這有點麻煩。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"콜로서스 베이스가 직접 이동하기엔 시간이 촉박한데…….","JPN":"コロッサスベースを移動させるには、時間が足りませんし……","ENG":"The Colossus Base can't relocate fast enough...","TWN":"要直接移動巨像基地，時間太緊迫了……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 참고해서 만들었다고 했지?","JPN":"線路転換器はエタニウムドライブを参考にして作ったと言っていたな？","ENG":"You said the Track Switcher was based on the Eternium Drive, right?","TWN":"線路轉換器是參考永恆之金引擎製造的對吧？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 그게 함선의 이터니움 드라이브를 대체할 수 있다는 말로 들리는데.","JPN":"なら、艦船のエタニウムドライブの代わりとして、十分代用できるという意味に聞こえるが。","ENG":"Then it sounds to me like it could replace a ship's Eternium Drive entirely.","TWN":"也就是說，它有可能替代艦船永恆之金引擎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"확인해 줄 수 있나?","JPN":"確認できるか？","ENG":"Can you confirm that?","TWN":"妳能幫忙確認看看嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠시만요…….","JPN":"少々お待ちくださいね……","ENG":"One moment...","TWN":"等一下……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 설계도를 구상한 시니어 이졸데만큼은 아니겠지만, 그 부분에 대해서 말씀드릴게요.","JPN":"はい。設計図を構想したシニア・イゾルデほどではありませんが、それについて説明いたします。","ENG":"Yes. I may not understand the schematics as deeply as Senior Isolde, but I can tell you this much.","TWN":"嗯，雖然我比不上設計圖的原作者Senior伊索德，但我可以說明那個部分。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"시니어 이졸데는 분명 함선에 탑재하는 것까지 고려하셨던 것 같아요.","JPN":"シニア・イゾルデは、きっと艦船への搭載まで考えておられたのでしょう。","ENG":"It seems Senior Isolde definitely designed it with ship-mounting in mind.","TWN":"Senior伊索德確實曾考慮過安裝在艦船上的可能性。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"몇 개의 연결부를 함선의 동력원과 연결한다면… 차원 도약의 역할은 물론이고…….","JPN":"いくつかの連結部を艦船の動力源に繋げば……次元跳躍の役割はもちろん……","ENG":"If we connect several couplings to the ship's power core... it could handle dimension jumps...","TWN":"只要把幾個接點連到艦船的能源核心……不只能進行次元跳躍……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"본래 목적인 그림자의 차원 도약 경로를 뒤트는 것도 가능할 거예요.","JPN":"本来の目的であるシャドウの次元跳躍経路を曲げることも可能と思われます。","ENG":"and even twist a Shadow's jump trajectory, which is its original purpose.","TWN":"甚至能達成原本干擾影子次元跳躍路徑的目的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마땅한 장소가 없으니, 함선을 통해 선로전환기를 가동시키겠다라…….","JPN":"ちょうどいい場所がないので、艦船を通じて線路転換器を稼働する……","ENG":"So if there's no suitable site, we'd activate the Track Switcher through the ship itself...","TWN":"既然找不到合適地點，那就透過艦船啟動轉換器……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 좋은 방법이라고 생각해요!","JPN":"私はいい方法だと思います！","ENG":"I think that's an excellent idea!","TWN":"我覺得是個好方法。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"빠른 상황 판단은 해적의 생명줄이거든.","JPN":"迅速な状況判断は海賊の命綱だからな。","ENG":"Quick judgment is a pirate's lifeline.","TWN":"迅速判斷情勢是海盜的命脈。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 듣기론, 알파트릭스의 회장은 다양한 분야에서 천재라고 들었어.","JPN":"アルファトリックス会長は様々な分野での天才だと聞いた。","ENG":"And I've heard Alphatrix's President is a genius in multiple fields.","TWN":"我聽說阿爾法崔克斯的會長是各領域的天才。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇다면 잠시, 프론트 베이의 임시 조선공이 되어줬으면 하는데, 응해줄 수 있겠나?","JPN":"なら、しばらくフロントベイの臨時造船師になってほしいのだが、受け入れてくれるか？","ENG":"In that case, I'd like you to serve as Front Bay's temporary shipwright. Would you be willing?","TWN":"那麼，我希望妳能暫時成為前灣的臨時造船師，可以嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"조선공이라… 후훗, 그게 시니어님이 원하시는 거라면.","JPN":"造船師ですか……ふふっ、それがシニアのお望みなら。","ENG":"A shipwright...? Fufu, if that's what you'd like, Senior.","TWN":"造船師啊……呵呵，如果Senior您希望的話，"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};